// T618 FlowPublicationOrchestrator — DFS cycle detection + type check + OCC
const WHITE = 'WHITE' as const;
const GRAY = 'GRAY' as const;
const BLACK = 'BLACK' as const;

private detectCycle(nodes: Record<string, unknown>[], edges: Record<string, unknown>[]): string | null {
  const adj = new Map<string, string[]>();
  for (const node of nodes) adj.set(node['nodeId'] as string, []);
  for (const edge of edges) {
    const src = edge['sourceNodeId'] as string;
    adj.get(src)?.push(edge['targetNodeId'] as string);
  }
  const color = new Map<string, string>();
  for (const node of nodes) color.set(node['nodeId'] as string, WHITE);
  const dfs = (nodeId: string): string | null => {
    color.set(nodeId, GRAY);
    for (const neighbor of (adj.get(nodeId) ?? [])) {
      if (color.get(neighbor) === GRAY) return nodeId; // cycle detected
      if (color.get(neighbor) === WHITE) { const r = dfs(neighbor); if (r) return r; }
    }
    color.set(nodeId, BLACK);
    return null;
  };
  for (const node of nodes) if (color.get(node['nodeId'] as string) === WHITE) { const r = dfs(node['nodeId'] as string); if (r) return r; }
  return null;
}

private findTypeIncompatibleEdge(edges: Record<string, unknown>[]): Record<string, unknown> | null {
  return edges.find(e => e['sourceOutputType'] !== e['targetInputType']) ?? null;
}
